text = ""

text2 = "0123456789QWERTYUIOPASDFGHJKLZXCVBNMqwertyuiopasdfghjklzxcvbnm"
text3 = {text2[i]:i for i in range(62)}
li = [0]*100000
dum = 0
for i in range(100000):
    for j in range(3):
        dum += text3[text[i*3+j]] * pow(62,j)
    li[i] = dum
#print(text[(100-1)*3:(100-1)*3+3])
a = int(input())
for i in range(a):
    b = int(input())
    print(f"Case #{i+1}: {li[b-1]*4}")

